func (mmUpdateVacancy *mVacancyStorageMockUpdateVacancy) invocationsDone() bool {
	if len(mmUpdateVacancy.expectations) == 0 && mmUpdateVacancy.defaultExpectation == nil && mmUpdateVacancy.mock.funcUpdateVacancy == nil {
		return true
	}

	totalInvocations := mm_atomic.LoadUint64(&mmUpdateVacancy.mock.afterUpdateVacancyCounter)
	expectedInvocations := mm_atomic.LoadUint64(&mmUpdateVacancy.expectedInvocations)

	return totalInvocations > 0 && (expectedInvocations == 0 || expectedInvocations == totalInvocations)
}

// UpdateVacancy implements mm_vacancy_service.VacancyStorage
func (mmUpdateVacancy *VacancyStorageMock) UpdateVacancy(ctx context.Context, in domain.UpdateVacancyInput) (vp1 *domain.Vacancy, err error) {
	mm_atomic.AddUint64(&mmUpdateVacancy.beforeUpdateVacancyCounter, 1)
	defer mm_atomic.AddUint64(&mmUpdateVacancy.afterUpdateVacancyCounter, 1)

	mmUpdateVacancy.t.Helper()

	if mmUpdateVacancy.inspectFuncUpdateVacancy != nil {
		mmUpdateVacancy.inspectFuncUpdateVacancy(ctx, in)
	}

	mm_params := VacancyStorageMockUpdateVacancyParams{ctx, in}

	// Record call args
	mmUpdateVacancy.UpdateVacancyMock.mutex.Lock()
	mmUpdateVacancy.UpdateVacancyMock.callArgs = append(mmUpdateVacancy.UpdateVacancyMock.callArgs, &mm_params)
	mmUpdateVacancy.UpdateVacancyMock.mutex.Unlock()

	for _, e := range mmUpdateVacancy.UpdateVacancyMock.expectations {
		if minimock.Equal(*e.params, mm_params) {
			mm_atomic.AddUint64(&e.Counter, 1)
			return e.results.vp1, e.results.err
		}
	}

	if mmUpdateVacancy.UpdateVacancyMock.defaultExpectation != nil {
		mm_atomic.AddUint64(&mmUpdateVacancy.UpdateVacancyMock.defaultExpectation.Counter, 1)
		mm_want := mmUpdateVacancy.UpdateVacancyMock.defaultExpectation.params
		mm_want_ptrs := mmUpdateVacancy.UpdateVacancyMock.defaultExpectation.paramPtrs

		mm_got := VacancyStorageMockUpdateVacancyParams{ctx, in}

		if mm_want_ptrs != nil {

			if mm_want_ptrs.ctx != nil && !minimock.Equal(*mm_want_ptrs.ctx, mm_got.ctx) {
				mmUpdateVacancy.t.Errorf("VacancyStorageMock.UpdateVacancy got unexpected parameter ctx, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmUpdateVacancy.UpdateVacancyMock.defaultExpectation.expectationOrigins.originCtx, *mm_want_ptrs.ctx, mm_got.ctx, minimock.Diff(*mm_want_ptrs.ctx, mm_got.ctx))
			}

			if mm_want_ptrs.in != nil && !minimock.Equal(*mm_want_ptrs.in, mm_got.in) {
				mmUpdateVacancy.t.Errorf("VacancyStorageMock.UpdateVacancy got unexpected parameter in, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmUpdateVacancy.UpdateVacancyMock.defaultExpectation.expectationOrigins.originIn, *mm_want_ptrs.in, mm_got.in, minimock.Diff(*mm_want_ptrs.in, mm_got.in))
			}

		} else if mm_want != nil && !minimock.Equal(*mm_want, mm_got) {
			mmUpdateVacancy.t.Errorf("VacancyStorageMock.UpdateVacancy got unexpected parameters, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
				mmUpdateVacancy.UpdateVacancyMock.defaultExpectation.expectationOrigins.origin, *mm_want, mm_got, minimock.Diff(*mm_want, mm_got))
		}

		mm_results := mmUpdateVacancy.UpdateVacancyMock.defaultExpectation.results
		if mm_results == nil {
			mmUpdateVacancy.t.Fatal("No results are set for the VacancyStorageMock.UpdateVacancy")
		}
		return (*mm_results).vp1, (*mm_results).err
	}
	if mmUpdateVacancy.funcUpdateVacancy != nil {
		return mmUpdateVacancy.funcUpdateVacancy(ctx, in)
	}
	mmUpdateVacancy.t.Fatalf("Unexpected call to VacancyStorageMock.UpdateVacancy. %v %v", ctx, in)
	return
}

