// MinimockUpdateVacancyDone returns true if the count of the UpdateVacancy invocations corresponds
// the number of defined expectations
func (m *VacancyStorageMock) MinimockUpdateVacancyDone() bool {
	if m.UpdateVacancyMock.optional {
		// Optional methods provide '0 or more' call count restriction.
		return true
	}

	for _, e := range m.UpdateVacancyMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			return false
		}
	}

	return m.UpdateVacancyMock.invocationsDone()
}

// MinimockUpdateVacancyInspect logs each unmet expectation
func (m *VacancyStorageMock) MinimockUpdateVacancyInspect() {
	for _, e := range m.UpdateVacancyMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			m.t.Errorf("Expected call to VacancyStorageMock.UpdateVacancy at\n%s with params: %#v", e.expectationOrigins.origin, *e.params)
		}
	}

	afterUpdateVacancyCounter := mm_atomic.LoadUint64(&m.afterUpdateVacancyCounter)
	// if default expectation was set then invocations count should be greater than zero
	if m.UpdateVacancyMock.defaultExpectation != nil && afterUpdateVacancyCounter < 1 {
		if m.UpdateVacancyMock.defaultExpectation.params == nil {
			m.t.Errorf("Expected call to VacancyStorageMock.UpdateVacancy at\n%s", m.UpdateVacancyMock.defaultExpectation.returnOrigin)
		} else {
			m.t.Errorf("Expected call to VacancyStorageMock.UpdateVacancy at\n%s with params: %#v", m.UpdateVacancyMock.defaultExpectation.expectationOrigins.origin, *m.UpdateVacancyMock.defaultExpectation.params)
		}
	}
	// if func was set then invocations count should be greater than zero
	if m.funcUpdateVacancy != nil && afterUpdateVacancyCounter < 1 {
		m.t.Errorf("Expected call to VacancyStorageMock.UpdateVacancy at\n%s", m.funcUpdateVacancyOrigin)
	}

	if !m.UpdateVacancyMock.invocationsDone() && afterUpdateVacancyCounter > 0 {
		m.t.Errorf("Expected %d calls to VacancyStorageMock.UpdateVacancy at\n%s but found %d calls",
			mm_atomic.LoadUint64(&m.UpdateVacancyMock.expectedInvocations), m.UpdateVacancyMock.expectedInvocationsOrigin, afterUpdateVacancyCounter)
	}
}

// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *VacancyStorageMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockArchiveVacancyInspect()

			m.MinimockCreateVacancyInspect()

			m.MinimockGetVacancyInspect()

			m.MinimockListVacanciesInspect()

			m.MinimockUpdateVacancyInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *VacancyStorageMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *VacancyStorageMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockArchiveVacancyDone() &&
		m.MinimockCreateVacancyDone() &&
		m.MinimockGetVacancyDone() &&
		m.MinimockListVacanciesDone() &&
		m.MinimockUpdateVacancyDone()
}
